mapper.select:
SELECT a.no, a.content_id, a.title, a.content_type_id, a.sido_code, a.gugun_code, a.first_image1, a.first_image2, a.latitude, a.longitude, a.addr1, a.addr2, ST_Distance( a.geom::geography, ST_SetSRID(ST_MakePoint(#{longitude}, #{latitude}), 4326)::geography ) AS distance_meters FROM attractions a WHERE a.geom IS NOT NULL AND a.latitude IS NOT NULL AND a.longitude IS NOT NULL AND ST_DWithin( a.geom::geography, ST_SetSRID(ST_MakePoint(#{longitude}, #{latitude}), 4326)::geography, #{radiusMeters} )
AND a.content_type_id = #{contentTypeId}
ORDER BY distance_meters ASC, a.no ASC LIMIT #{limit}
